    "help": {
      "udl_modal_title": "Hagaha Universal Design for Learning",
      "udl_modal_desc": "Hagahaan dhameystiran wuxuu kaa caawiyaa inaad fahamto mabaadi'da UDL oo aad ku dabaqdo waxbarashadaada. Isticmaal si aad u abuurto khibradaha barashada oo dheeraad ah oo la heli karo oo soo-jiidasho leh dhammaan ardayda.",
      "header_actions_title": "Ficillada Madaxa",
      "header_actions_desc": "Kontorool helitaan degdeg ah oo dejinta luqadda, doorashooyinka helitaanka, iyo beddelka habka isticmaalaha. Habayso khibradaada AlloFlow halkan.",
      "header_utils_title": "Kontoroolka Faa'iidooyinka",
      "header_utils_desc": "Faa'iidooyin muhiim ah oo ay ku jiraan maaraynta mashruuca, khayraadyada caawimada, iyo bedel habka isticmaalaha. Beddel inta u dhaxaysa habka Macallinka iyo Ardayga ama hel shaqada la kaydiyay.",
      "header_tools_title": "Aaladaha Degdega ah",
      "header_tools_desc": "Aaladaha awoodda leh ee samaynta nuxurka iyo kaalmada AI. Hel goobta qoraalka, kaalmiyaha wadahadalka, iyo sifooyinka kale ee waxsoo-saarka.",
      "lesson_plan_title": "Qorshaynta Casharka",
      "lesson_plan_desc": "Habee parametarrada casharkaaga oo ay ku jiraan muddada, heerka fasalka, qaybaha nuxurka, iyo yoolalka waxbarashada. Dejinta waxay kaa caawiyaan inaad u habooneyso nuxurka AI-gu sameeyay baahiyahaaga gaarka ah.",
      "tool_udl_title": "Bedelka Hagaha UDL",
      "tool_udl_desc": "Bedel galbeedka Universal Design for Learning si aad u aragto tilmaamaha iyo hubinta intaad shaqaynayso. Isticmaal si aad u hubsato in qalabkaagu la heli karo oo soo-jiidasho leh yahay.",
      "tool_chat_title": "Kaalmiyaha Wadahadalka AI",
      "tool_chat_desc": "Fur kaalmiyaha wadahadalka AI si aad u hesho caawimo is-dhexgal ah oo nuxurkaaga ah. Weydii su'aalo, hel talooyin, ama codso beddelo qalabkaaga.",
      "tool_writing_title": "Goobta Qoraalka",
      "tool_writing_desc": "Bilow bay'adda qoraalka iskaashiga halkaas oo ardaydu ka qori karaan, dib u eegi karaan, oo helaan jawaab AI-gu bixiyo qoraalkooda.",
      "sidebar_analysis_title": "Falanqaynta Qoraalka",
      "sidebar_analysis_desc": "Falanqayn AI ku saleysan qoraalkaaga isha oo ay ku jirto qiimaynta heerka akhrinta, aqoonsiga erayada muhiimka ah, iyo kala-jajabka qaab-dhismeedka nuxurka.",
      "sidebar_glossary_title": "Liiska Erayada Aqliga ah",
      "sidebar_glossary_desc": "Erayada si toos ah laga soo saaray oo leh qeexitaano, tarjumaado, iyo astaamo muuqaal. Tafatir erayada, ku dar tarjumaado, oo samee kaadhka jeexa.",
      "sidebar_simplified_title": "Noocyo Fudud",
      "sidebar_simplified_desc": "Hel noocyo kala duwan oo qoraalkaaga ah heerar akhrineed kala duwan. Samee nuxur fudud, noocyo labo-luqadood dhinac-ku-dhinac ah, iyo qoraalo la beddelay.",
      "sidebar_outline_title": "Habaynta Muuqaalka",
      "sidebar_outline_desc": "Samee matalaad muuqaal habaysan oo nuxurka oo ay ku jiraan khariidadaha fikradaha, jaantusyada socodka, jaantusyada Venn, iyo habayn sabab-saamayn.",
      "sidebar_visuals_title": "Taageerada Muuqaalka",
      "sidebar_visuals_desc": "Sawiro AI lagu sameeyay iyo kaalmooyin muuqaal si loo taageero faham-galka. Samee muuqaalo gaar ah ama xirmooyin sawir oo la kor u qaaday oo nuxurka ah.",
      "sidebar_faq_title": "Sameeyaha FAQ",
      "sidebar_faq_desc": "Samee su'aalo si caadi ah loo weydiiyo oo ay ardaydu ka qabi karaan nuxurka. Wax fiican oo lagu filsado wareerka oo lagu diyaariyo sharaxaadyo.",
      "sidebar_scaffolds_title": "Tageerooyinka Waxbarashada",
      "sidebar_scaffolds_desc": "Hel istiraatiijiyado waxbarasho, su'aalo wadahadal, iyo hawlo tageer leh oo u habboon nuxurkaaga. Waxaa ku jira habayn jaantus iyo ku-celcelis la hago.",
      "sidebar_quiz_title": "Tikidhada Bixinta & Quiz-yada",
      "sidebar_quiz_desc": "Samee qiimaynta dhinaca ee degdega ah si aad u hubiso faham-galka. Samee qaababka MCQ, jawaabaha gaaban, ama quiz-yada is-dhexgalka.",
      "sidebar_brainstorm_title": "Fikrado Ka-qaybgalka",
      "sidebar_brainstorm_desc": "Hel soo-jiidashooyin hal-abuur leh, hawlo bilow, iyo istiraatiijiyado ka-qaybgal si aad u soo bandhigto nuxurkaaga oo aad u xidhilineyso xiisaha ardayga.",
      "sidebar_games_title": "Ciyaaro Is-dhexgal",
      "sidebar_games_desc": "Samee ciyaaro waxbarasho oo ay ku jiraan kaadhka jeexa, halxiraalaha crossword, kaadhka BINGO, iyo ciyaaraha habaynta xusuusta adigoo isticmaalaya erayada nuxurkaaga.",
      "sidebar_resources_title": "Xirmada Khayraadka",
      "sidebar_resources_desc": "Soo dejii xirmooyin khayraad dhameystiran oo ay ku jiraan dhammaan qalabka la sameeyay qaab PDF oo daabacan oo loogu talagalay fasalka.",
      "sidebar_adventure_title": "Halganada Waxbarashada",
      "sidebar_adventure_desc": "Samee sheekooyinka 'doorashada-go'aanka' ee is-dhexgalka ah ee ku saleysan nuxurkaaga. Ardaydu way go'aamiyaan oo waxay sahmiyaan fikradaha iyada oo loo marayo ciyaarta sheekada.",
      "sidebar_interview_title": "Wareysiyo Taariikheed",
      "sidebar_interview_desc": "Samee shakhsiyaad AI ah oo shaqsiyaadka taariikhiga ah ama jilayaasha qoraalka loogu talagalay wareysiyo iyo doodaha la ciyaaray. Soo nooleyso ilaha aasaasiga ah.",
      "default_title": "Mawduuca Caawimada",
      "default_desc": "Macluumaadka sifadan halkan ayuu ka soo muuqan doonaa. Riix qaybta kasta oo leh astaanta caawimada si aad wax badan u barato."
    },
